{
  "resource": {
    "metadata": {
      "title": "engine-gating-a",
      "author": "Wazuh Inc.",
      "description": "Parent integration for decoder/kvdb/rule used by engine gating tests.",
      "documentation": "engine-validation-gating",
      "references": ["https://wazuh.com"]
    },
    "category": "system-activity",
    "enabled": true
  }
}

{
  "resource": {
    "metadata": {
      "title": "engine-gating-b",
      "author": "Wazuh Inc.",
      "description": "Standalone integration used to test engine-skip on integration-only promotion.",
      "documentation": "engine-validation-gating",
      "references": ["https://wazuh.com"]
    },
    "category": "system-activity",
    "enabled": true
  }
}

{
  "integration": "{{integration_a_id}}",
  "resource": {
    "enabled": true,
    "metadata": {
      "compatibility": "All wazuh events.",
      "description": "Decoder used by engine gating tests.",
      "module": "wazuh",
      "references": ["https://documentation.wazuh.com/"],
      "title": "engine-gating decoder",
      "versions": ["Wazuh 5.*"]
    },
    "name": "decoder/engine-gating-a/0",
    "normalize": [
      { "map": [ { "@timestamp": "get_date()" } ] }
    ]
  }
}

{
  "integration": "{{integration_a_id}}",
  "resource": {
    "enabled": true,
    "metadata": {
      "title": "engine-gating kvdb",
      "author": "Wazuh Inc.",
      "description": "KVDB used by engine gating tests.",
      "references": ["https://wazuh.com"]
    },
    "content": {
      "foo": "bar"
    }
  }
}

{
  "integration": "{{integration_a_id}}",
  "resource": {
    "logsource": { "product": "engine-gating-a" },
    "tags": ["attack.credential-access", "attack.t1555.005"],
    "falsepositives": ["Unknown"],
    "level": "high",
    "status": "test",
    "references": [],
    "metadata": {
      "author": "Wazuh",
      "title": "Engine gating rule",
      "description": "Rule used by engine gating tests"
    },
    "compliance": { "pci_dss": ["6.2", "11.4"], "gdpr": ["32"] },
    "mitre": { "tactic": ["TA0040"], "technique": ["T1499"] },
    "detection": {
      "condition": "selection",
      "selection": { "message|contains": "engine-gating" }
    }
  }
}

{
  "space": "draft",
  "resource": {
    "name": "filter/engine-gating-a/0",
    "enabled": true,
    "type": "pre-filter",
    "check": "$wazuh.integration.category == 'system-activity'",
    "metadata": {
      "title": "Engine gating filter",
      "description": "Filter used by engine gating tests.",
      "author": "Wazuh, Inc."
    }
  }
}

{
  "resource": {
    "metadata": {
      "title": "engine-gating-c",
      "author": "Wazuh Inc.",
      "description": "Integration used in folder 3 to test engine invocation via existing destination resources.",
      "documentation": "engine-validation-gating",
      "references": ["https://wazuh.com"]
    },
    "category": "system-activity",
    "enabled": true
  }
}

{
  "integration": "{{integration_c_id}}",
  "resource": {
    "logsource": { "product": "engine-gating-c" },
    "tags": ["attack.credential-access"],
    "falsepositives": ["Unknown"],
    "level": "medium",
    "status": "test",
    "references": [],
    "metadata": {
      "author": "Wazuh",
      "title": "Engine gating rule B",
      "description": "Rule used in folder 3 engine gating tests"
    },
    "compliance": { "pci_dss": ["6.2"] },
    "mitre": { "tactic": ["TA0040"], "technique": ["T1499"] },
    "detection": {
      "condition": "selection",
      "selection": { "message|contains": "engine-gating-c" }
    }
  }
}

